import { useState } from "react";

// ── Images ────────────────────────────────────────────────────────────────────
const IMG_MARCUS = "data:image/png;base64,";
const IMG_ELENA = "data:image/png;base64,";
const IMG_JULIAN = "data:image/png;base64,";
const IMG_CERT_PHOTO = "data:image/png;base64,";

// ── Logo mark ─────────────────────────────────────────────────────────────────
const IMG_CG_LOGO_REAL = "data:image/png;base64,";
function ConcordLogo({ size = "nav" }) {
  const h = size === "footer" ? 44 : 36;
  return <img src={IMG_CG_LOGO_REAL} alt="Concord Group" style={{ height: h, width: "auto", display: "block" }} />;
}

// ── Helpers ───────────────────────────────────────────────────────────────────
const ArrowRight = ({ color = "#fff", size = 14 }) => (
  <svg width={size} height={size} viewBox="0 0 24 24" fill="none">
    <path d="M5 12h14M13 6l6 6-6 6" stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
  </svg>
);
const ChevronDown = () => (
  <svg width="10" height="6" viewBox="0 0 10 6" fill="none">
    <path d="M1 1l4 4 4-4" stroke="currentColor" strokeWidth="1.7" strokeLinecap="round" strokeLinejoin="round"/>
  </svg>
);
const LI = () => <svg width="18" height="18" viewBox="0 0 24 24" fill="currentColor"><path d="M16 8a6 6 0 016 6v7h-4v-7a2 2 0 00-2-2 2 2 0 00-2 2v7h-4v-7a6 6 0 016-6zM2 9h4v12H2zm2-3a2 2 0 110-4 2 2 0 010 4z"/></svg>;
const YT = () => <svg width="18" height="18" viewBox="0 0 24 24" fill="currentColor"><path d="M22.5 6.4a2.8 2.8 0 00-2-2C18.9 4 12 4 12 4s-6.9 0-8.5.4a2.8 2.8 0 00-2 2A29 29 0 001 12a29 29 0 00.5 5.6 2.8 2.8 0 002 2C5.1 20 12 20 12 20s6.9 0 8.5-.4a2.8 2.8 0 002-2A29 29 0 0023 12a29 29 0 00-.5-5.6zM9.75 15V9l5.75 3-5.75 3z"/></svg>;
const XI = () => <svg width="18" height="18" viewBox="0 0 24 24" fill="currentColor"><path d="M18.2 2.25h3.3l-7.2 8.3 8.5 11.2H16.2l-5.2-6.8-6 6.8H1.7l7.7-8.8L1.3 2.25H8.1l4.7 6.2 5.4-6.2zm-1.2 17.5h1.8L7.1 4.1H5.1l11.9 15.65z"/></svg>;

function DropItem({ children }) {
  const [hov, setHov] = useState(false);
  return (
    <button onMouseEnter={() => setHov(true)} onMouseLeave={() => setHov(false)} style={{
      display: "block", width: "100%", textAlign: "left", padding: "10px 20px",
      fontSize: 13, color: hov ? "#fff" : "#9CA3AF",
      background: hov ? "rgba(255,255,255,0.05)" : "transparent",
      borderLeft: `2px solid ${hov ? "#E31E24" : "transparent"}`,
      cursor: "pointer", transition: "all 0.12s", border: "none",
    }}>{children}</button>
  );
}

function NavItem({ label, items, active }) {
  const [open, setOpen] = useState(false);
  return (
    <div style={{ position: "relative" }}
      onMouseEnter={() => setOpen(true)} onMouseLeave={() => setOpen(false)}>
      <button style={{
        display: "inline-flex", alignItems: "center", gap: 3,
        height: 64, padding: "0 10px", background: "none", border: "none",
        fontSize: 12.5, color: active ? "#E31E24" : "#fff",
        fontWeight: active ? 600 : 400, cursor: "pointer",
        borderBottom: active ? "2px solid #E31E24" : "2px solid transparent",
        transition: "color 0.15s",
      }}
        onMouseEnter={e => { if (!active) e.currentTarget.style.color = "#E31E24"; }}
        onMouseLeave={e => { if (!active) e.currentTarget.style.color = "#fff"; }}
      >
        {label}{items && <span style={{ opacity: 0.6, marginLeft: 2 }}><ChevronDown /></span>}
      </button>
      {items && open && (
        <div style={{
          position: "absolute", top: 64, left: 0, zIndex: 99999,
          background: "#0a0a0a", border: "1px solid rgba(255,255,255,0.1)",
          borderRadius: 8, minWidth: 220, padding: "6px 0",
          boxShadow: "0 20px 60px rgba(0,0,0,0.95)",
        }}>
          {items.map(item => <DropItem key={item}>{item}</DropItem>)}
        </div>
      )}
    </div>
  );
}

function FootLink({ children }) {
  const [hov, setHov] = useState(false);
  return (
    <button onMouseEnter={() => setHov(true)} onMouseLeave={() => setHov(false)} style={{
      background: "none", border: "none", textAlign: "left", padding: 0,
      fontSize: 13, color: hov ? "#fff" : "#6B7280", cursor: "pointer", transition: "color 0.15s",
    }}>{children}</button>
  );
}

function CertRow({ icon, title, sub }) {
  const [hov, setHov] = useState(false);
  return (
    <div onMouseEnter={() => setHov(true)} onMouseLeave={() => setHov(false)} style={{
      display: "flex", alignItems: "center", gap: 16,
      border: `1px solid ${hov ? "rgba(227,30,36,0.4)" : "rgba(255,255,255,0.1)"}`,
      borderRadius: 8, padding: "18px 22px",
      background: hov ? "rgba(227,30,36,0.04)" : "transparent",
      transition: "all 0.2s",
    }}>
      <div style={{
        width: 40, height: 40, borderRadius: 8,
        border: "1px solid rgba(227,30,36,0.3)",
        display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0,
      }}>{icon}</div>
      <div>
        <div style={{ fontSize: 14, fontWeight: 700, color: "#fff", marginBottom: 2 }}>{title}</div>
        <div style={{ fontSize: 12, color: "#6B7280" }}>{sub}</div>
      </div>
    </div>
  );
}

function LeaderCard({ photo, name, role, desc }) {
  const [hov, setHov] = useState(false);
  return (
    <div onMouseEnter={() => setHov(true)} onMouseLeave={() => setHov(false)} style={{
      background: hov ? "#141414" : "#0d0d0d",
      border: `1px solid ${hov ? "rgba(227,30,36,0.35)" : "rgba(255,255,255,0.06)"}`,
      borderRadius: 12, overflow: "hidden", transition: "all 0.22s",
      transform: hov ? "translateY(-5px)" : "none",
      boxShadow: hov ? "0 20px 56px rgba(0,0,0,0.7)" : "none",
    }}>
      <div style={{ height: 320, overflow: "hidden", position: "relative" }}>
        <img src={photo} alt={name} style={{
          width: "100%", height: "100%", objectFit: "cover", objectPosition: "top center",
          display: "block", filter: "grayscale(100%)",
          transform: hov ? "scale(1.04)" : "scale(1)", transition: "transform 0.35s",
        }} />
        <div style={{
          position: "absolute", bottom: 0, left: 0, right: 0, height: 80,
          background: hov
            ? "linear-gradient(to top, rgba(227,30,36,0.18), transparent)"
            : "linear-gradient(to top, rgba(0,0,0,0.4), transparent)",
          transition: "background 0.22s",
        }} />
      </div>
      <div style={{ padding: "28px 28px 32px" }}>
        <h3 style={{ fontSize: 22, fontWeight: 800, color: "#fff", marginBottom: 5 }}>{name}</h3>
        <p style={{ fontSize: 13, color: "#E31E24", fontWeight: 600, marginBottom: 16, letterSpacing: 0.3 }}>{role}</p>
        <p style={{ fontSize: 14, color: "#9CA3AF", lineHeight: 1.75 }}>{desc}</p>
      </div>
    </div>
  );
}

function ControlRoomBg() {
  return (
    <svg viewBox="0 0 1440 820" xmlns="http://www.w3.org/2000/svg"
      style={{ position: "absolute", inset: 0, width: "100%", height: "100%", opacity: 0.18 }}>
      <defs>
        <radialGradient id="g1" cx="50%" cy="50%" r="50%">
          <stop offset="0%" stopColor="#4477ff" stopOpacity="0.8"/>
          <stop offset="100%" stopColor="#4477ff" stopOpacity="0"/>
        </radialGradient>
        <radialGradient id="g2" cx="50%" cy="50%" r="50%">
          <stop offset="0%" stopColor="#3355cc" stopOpacity="0.6"/>
          <stop offset="100%" stopColor="#3355cc" stopOpacity="0"/>
        </radialGradient>
        <filter id="b1"><feGaussianBlur stdDeviation="3"/></filter>
        <filter id="b2"><feGaussianBlur stdDeviation="6"/></filter>
      </defs>
      <rect width="1440" height="820" fill="#050810"/>
      {[120,320,520,720,920,1120].map((x,i) => (
        <g key={`r1${i}`}>
          <rect x={x} y={50} width={170} height={110} rx="4" fill="#0a1020" stroke="#1a2540" strokeWidth="1.5"/>
          <rect x={x+4} y={54} width={162} height={102} rx="3" fill="#060c1a"/>
          <rect x={x+4} y={54} width={162} height={102} rx="3" fill="url(#g1)" opacity="0.4" filter="url(#b1)"/>
          <polyline points={`${x+15},${90+Math.sin(i)*10} ${x+40},${75+i*3} ${x+65},${95-i*2} ${x+90},80 ${x+115},${100-i*3} ${x+145},85`} fill="none" stroke="#3366ff" strokeWidth="1.2" opacity="0.7"/>
        </g>
      ))}
      {[80,310,560,810,1060,1260].map((x,i) => (
        <g key={`r2${i}`}>
          <rect x={x} y={200} width={200} height={140} rx="4" fill="#080f1e" stroke="#162035" strokeWidth="1.5"/>
          <rect x={x+4} y={204} width={192} height={132} rx="3" fill="#040912"/>
          <rect x={x+4} y={204} width={192} height={132} rx="3" fill="url(#g1)" opacity={0.3+i*0.04} filter="url(#b1)"/>
          {i%2===0 ? (
            <g>
              <circle cx={x+100} cy={270} r={42} fill="none" stroke="#2255dd" strokeWidth="1" opacity="0.5"/>
              <circle cx={x+100} cy={270} r={28} fill="none" stroke="#3366ff" strokeWidth="1.5" opacity="0.7"/>
              <circle cx={x+100} cy={270} r={12} fill="#1133aa" opacity="0.5"/>
              <line x1={x+100} y1={228} x2={x+100} y2={270} stroke="#5577ff" strokeWidth="1.2" opacity="0.8"/>
            </g>
          ) : (
            <polyline points={`${x+14},${300} ${x+44},${260+i} ${x+74},285 ${x+104},255 ${x+134},275 ${x+164},260 ${x+186},270`} fill="none" stroke="#4488ff" strokeWidth="1.5" opacity="0.7"/>
          )}
        </g>
      ))}
      {[160,400,650,900,1150].map((x,i) => (
        <g key={`r3${i}`}>
          <rect x={x} y={395} width={180} height={110} rx="4" fill="#070d1c" stroke="#141e30" strokeWidth="1.5"/>
          <rect x={x+4} y={399} width={172} height={102} rx="3" fill="#030810"/>
          <rect x={x+4} y={399} width={172} height={102} rx="3" fill="url(#g2)" opacity={0.25+i*0.05} filter="url(#b1)"/>
          <polyline points={`${x+14},460 ${x+40},${445+i} ${x+70},455 ${x+100},${440+i} ${x+130},450 ${x+160},442`} fill="none" stroke="#3355cc" strokeWidth="1.2" opacity="0.6"/>
        </g>
      ))}
      <rect x="0" y="520" width="1440" height="18" fill="#0c1525" opacity="0.8"/>
      <ellipse cx="360" cy="400" rx="280" ry="180" fill="url(#g1)" opacity="0.08" filter="url(#b2)"/>
      <ellipse cx="1080" cy="350" rx="260" ry="160" fill="url(#g2)" opacity="0.1" filter="url(#b2)"/>
    </svg>
  );
}

